package org.apache.commons.math.util;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.util.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.util.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.math.util.MathUtils;

public class StepDefs {

    private double[] array1;
    private double[] array2;
    private boolean result;

    @Given("two double arrays containing NaN values at the same positions")
    public void two_double_arrays_containing_NaN_values_at_the_same_positions() {
        array1 = new double[]{Double.NaN, 1.0, Double.NaN};
        array2 = new double[]{Double.NaN, 1.0, Double.NaN};
    }

    @When("I call MathUtils.equals(array1, array2)")
    public void i_call_MathUtils_equals_array1_array2() {
        try {
            result = MathUtils.equals(array1, array2);
        } catch (Exception e) {
            // Handle exception if necessary
            result = false;
        }
    }

    @Then("it should return false")
    public void it_should_return_false() {
        assertFalse(result);
    }

    @Then("specifically comparing [NaN] with [NaN] should return false")
    public void specifically_comparing_NaN_with_NaN_should_return_false() {
        boolean nanResult = MathUtils.equals(new double[]{Double.NaN}, new double[]{Double.NaN});
        assertFalse(nanResult);
    }

    @Then("comparing arrays with identical values except NaN should return false")
    public void comparing_arrays_with_identical_values_except_NaN_should_return_false() {
        double[] arr1 = new double[]{1.0, Double.NaN, 3.0};
        double[] arr2 = new double[]{1.0, Double.NaN, 3.0};
        boolean nanResult = MathUtils.equals(arr1, arr2);
        assertFalse(nanResult);
    }

    @Given("two double arrays containing NaN values at the same positions")
    public void given_two_double_arrays_containing_NaN_values_at_the_same_positions() {
        array1 = new double[]{Double.NaN, 2.0, Double.NaN};
        array2 = new double[]{Double.NaN, 2.0, Double.NaN};
    }

    @When("I call MathUtils.equalsIncludingNaN(array1, array2)")
    public void i_call_MathUtils_equalsIncludingNaN_array1_array2() {
        try {
            result = MathUtils.equalsIncludingNaN(array1, array2);
        } catch (Exception e) {
            // Handle exception if necessary
            result = false;
        }
    }

    @Then("it should return true")
    public void it_should_return_true() {
        assertTrue(result);
    }

    @Then("specifically comparing [NaN] with [NaN] should return true")
    public void specifically_comparing_NaN_with_NaN_should_return_true() {
        boolean nanResult = MathUtils.equalsIncludingNaN(new double[]{Double.NaN}, new double[]{Double.NaN});
        assertTrue(nanResult);
    }

    @Then("comparing arrays with identical values including NaN should return true")
    public void comparing_arrays_with_identical_values_including_NaN_should_return_true() {
        double[] arr1 = new double[]{1.0, Double.NaN, 3.0};
        double[] arr2 = new double[]{1.0, Double.NaN, 3.0};
        boolean nanResult = MathUtils.equalsIncludingNaN(arr1, arr2);
        assertTrue(nanResult);
    }

    @Given("two double arrays containing identical regular values")
    public void two_double_arrays_containing_identical_regular_values() {
        array1 = new double[]{1.0, 2.0, 3.0};
        array2 = new double[]{1.0, 2.0, 3.0};
    }

    @Given("two different double arrays that don't differ by NaN values")
    public void two_different_double_arrays_that_dont_differ_by_NaN_values() {
        array1 = new double[]{1.0, 2.0, 3.0};
        array2 = new double[]{4.0, 5.0, 6.0};
    }

    @Given("either one or both arrays are null")
    public void either_one_or_both_arrays_are_null() {
        array1 = null;
        array2 = new double[]{1.0, 2.0};
    }

    @Then("it should return true only if both arrays are null")
    public void it_should_return_true_only_if_both_arrays_are_null() {
        array1 = null;
        array2 = null;
        boolean nullBothResult = MathUtils.equals(array1, array2);
        assertTrue(nullBothResult);
    }

    @Then("comparing null with non-null arrays should return false")
    public void comparing_null_with_non_null_arrays_should_return_false() {
        array1 = null;
        array2 = new double[]{1.0, 2.0};
        boolean nullMixedResult = MathUtils.equals(array1, array2);
        assertFalse(nullMixedResult);

        array1 = new double[]{1.0, 2.0};
        array2 = null;
        boolean mixedNullResult = MathUtils.equals(array1, array2);
        assertFalse(mixedNullResult);
    }

    @Given("two double arrays with different lengths")
    public void two_double_arrays_with_different_lengths() {
        array1 = new double[]{1.0, 2.0};
        array2 = new double[]{1.0, 2.0, 3.0};
    }
}

